                let result = try decoder.decode(T.self, from: data)
                completion(.success(result))
            } catch {
                completion(.failure(error))
            }
        }
        task.resume()
    }

    func post<T: Encodable>(_ object: T, to url: URL, completion: @escaping (Result<T, Error>) -> Void) {
